/**
 * Izračun kalorij z MET formulo:
 *   kcal = MET × težaKg × čas_v_urah
 * Doda pribitek za vzpon: ~1 kcal/m vzpona (standardna ocena).
 */
private fun calculateCaloriesMet(
    activityType: ActivityType,
    durationSeconds: Long,
    weightKg: Double,
    elevationGainM: Float,
    avgSpeedKmh: Float
): Int {
    // 1. Omejimo nerealne hitrosti do 35 km/h za tek (GPS skoki)
    val safeSpeed = avgSpeedKmh.coerceIn(0f, 35f)

    // Prilagodi MET glede na hitrost z linearno interpolacijo,
    // da preprečimo stopničaste "GPS skoke" ki umetno dvignejo MET.
    val met = when (activityType) {
        ActivityType.RUN -> when {
            safeSpeed < 4f  -> safeSpeed // Linearno od 0 do 4
            safeSpeed < 8f  -> 4.0 + (safeSpeed - 4f) * 0.5 // 4 do 6
            safeSpeed < 10f -> 6.0 + (safeSpeed - 8f) * 1.0 // 6 do 8
            safeSpeed < 12f -> 8.0 + (safeSpeed - 10f) * 1.0 // 8 do 10
            safeSpeed < 14f -> 10.0 + (safeSpeed - 12f) * 0.75 // 10 do 11.5
            else            -> 11.5 + (safeSpeed - 14f) * 0.4
        }
        ActivityType.WALK -> when {
            safeSpeed < 3f -> 2.0 + (safeSpeed / 3f) * 0.5 // do 2.5
            safeSpeed < 5f -> 2.5 + (safeSpeed - 3f) * 0.5 // 2.5 do 3.5
            safeSpeed < 7f -> 3.5 + (safeSpeed - 5f) * 0.5 // 3.5 do 4.5
            else           -> 4.5 + (safeSpeed - 7f) * 0.3
        }
        ActivityType.SPRINT -> when {
            safeSpeed < 10f -> 8.0
            safeSpeed < 16f -> 8.0 + (safeSpeed - 10f) * 0.83 // 8 do 13
            safeSpeed < 20f -> 13.0 + (safeSpeed - 16f) * 0.75 // 13 do 16
            else            -> 16.0 + (safeSpeed - 20f) * 0.5
        }
        ActivityType.HIKE -> 6.0 + (elevationGainM / 100f) * 0.5 // Base 6.0 + gain
        ActivityType.CYCLING -> when {
            safeSpeed < 15f -> 4.0
            safeSpeed < 20f -> 6.0
            safeSpeed < 25f -> 8.0
            else            -> 10.0
        }
        else -> 5.0
    }.toDouble()

    // 2. Trajanje v urah
    val hours = durationSeconds / 3600.0
    // 3. Težo omejimo med 30kg in 200kg zaradi napak v profilu
    val safeWeight = weightKg.coerceIn(30.0, 200.0)

    val base = met * safeWeight * hours
    // Vzpon: ~0.8 kcal/m za povprečno težo 70 kg, skalira z dejansko težo. Omejen poskok GPS baz (max 2000m na log).
    val safeElevation = elevationGainM.coerceIn(0f, 2000f)
    val elevBonus = safeElevation * 0.8 * (safeWeight / 70.0)
    return (base + elevBonus).toInt().coerceAtLeast(0)
}

private fun calculateXP(activityType: ActivityType, distanceMeters: Double, timeSeconds: Long): Int {
    val baseFromDistance = distanceMeters / 100.0
    val baseFromTime = timeSeconds / 60.0
    val multiplier = when (activityType) {
        ActivityType.RUN, ActivityType.SPRINT -> 1.5
        ActivityType.HIKE, ActivityType.NORDIC -> 1.3
        ActivityType.WALK -> 1.0
        ActivityType.CYCLING -> 0.6
        ActivityType.SKIING, ActivityType.SNOWBOARD -> 0.5
        ActivityType.SKATING -> 1.0
    }
    return ((baseFromDistance + baseFromTime) * multiplier).toInt().coerceAtLeast(10)
}

@Composable
fun RunTrackerScreen(onBackPressed: () -> Unit, userProfile: UserProfile = UserProfile()) {
    val context = LocalContext.current
    val scope = rememberCoroutineScope()
    LaunchedEffect(Unit) {
        val config = Configuration.getInstance()
        config.userAgentValue = context.packageName
        config.cacheMapTileCount = 16.toShort()
        config.cacheMapTileOvershoot = 16.toShort()
    }

    // --- Tip aktivnosti ---
    var selectedActivity by remember { mutableStateOf(ActivityType.RUN) }
    var showActivityPicker by remember { mutableStateOf(false) }

    var service by remember { mutableStateOf<RunTrackingService?>(null) }
    var isBound by remember { mutableStateOf(false) }
    var isTracking by remember { mutableStateOf(false) }
    var isPaused by remember { mutableStateOf(false) }
    var locationPoints by remember { mutableStateOf<List<Location>>(emptyList()) }
    var elapsedSeconds by remember { mutableStateOf(0L) }
    var distanceMeters by remember { mutableStateOf(0.0) }
    var maxSpeed by remember { mutableStateOf(0f) }
    var avgSpeed by remember { mutableStateOf(0f) }
    var elevationGain by remember { mutableStateOf(0f) }
    var elevationLoss by remember { mutableStateOf(0f) }
    var mapView by remember { mutableStateOf<MapView?>(null) }
    var myLocationOverlay by remember { mutableStateOf<MyLocationNewOverlay?>(null) }
    var hasLocationPermission by remember { mutableStateOf(false) }
    var hasNotificationPermission by remember { mutableStateOf(true) }
    var showGpsDialog by remember { mutableStateOf(false) }
    var showDiscardDialog by remember { mutableStateOf(false) }
    var showSummary by remember { mutableStateOf(false) }
    var isSavingActivity by remember { mutableStateOf(false) }
    var routePolyline by remember { mutableStateOf<Polyline?>(null) }
    var isMapFollowingTarget by remember { mutableStateOf(true) }
    var finalDistance by remember { mutableStateOf(0.0) }
    var finalTime by remember { mutableStateOf(0L) }
    var finalMaxSpeed by remember { mutableStateOf(0f) }
    var finalAvgSpeed by remember { mutableStateOf(0f) }
    var finalElevationGain by remember { mutableStateOf(0f) }
    var finalElevationLoss by remember { mutableStateOf(0f) }
    var actualWeightKg by remember { mutableStateOf(70.0) }
    val uid = remember { com.example.myapplication.persistence.FirestoreHelper.getCurrentUserDocId() }

    LaunchedEffect(uid) {
        if (uid != null) {
            try {
                Firebase.firestore.collection("users").document(uid)
                    .collection("weightLogs")
                    .orderBy("date", com.google.firebase.firestore.Query.Direction.DESCENDING)
                    .limit(1).get()
                    .addOnSuccessListener { snap ->
                        val w = snap.documents.firstOrNull()?.get("weightKg") as? Number
                        if (w != null) actualWeightKg = w.toDouble()
                    }
            } catch (_: Exception) {}
        }
    }

    val serviceConnection = remember {
        object : ServiceConnection {
            override fun onServiceConnected(name: ComponentName?, binder: IBinder?) {
                service = (binder as? RunTrackingService.LocalBinder)?.getService(); isBound = true
            }
            override fun onServiceDisconnected(name: ComponentName?) { service = null; isBound = false }
        }
    }

    LaunchedEffect(Unit) { context.bindService(Intent(context, RunTrackingService::class.java), serviceConnection, Context.BIND_AUTO_CREATE) }
    DisposableEffect(Unit) {
        onDispose {
            if (isBound) try { context.unbindService(serviceConnection) } catch (_: Exception) {}
            myLocationOverlay?.disableMyLocation(); myLocationOverlay?.disableFollowLocation(); mapView?.onDetach()
        }
    }
    LaunchedEffect(service) { service?.isTracking?.collect { isTracking = it } }
    LaunchedEffect(service) { service?.isPaused?.collect { isPaused = it } }
    LaunchedEffect(service) { service?.locationPoints?.collect { locationPoints = it } }
    LaunchedEffect(service) { service?.elapsedSeconds?.collect { elapsedSeconds = it } }
    LaunchedEffect(service) { service?.distanceMeters?.collect { distanceMeters = it } }
    LaunchedEffect(service) { service?.maxSpeed?.collect { maxSpeed = it } }
    LaunchedEffect(service) { service?.avgSpeed?.collect { avgSpeed = it } }
    LaunchedEffect(service) { service?.elevationGain?.collect { elevationGain = it } }
    LaunchedEffect(service) { service?.elevationLoss?.collect { elevationLoss = it } }

    LaunchedEffect(Unit) {
        hasLocationPermission = ContextCompat.checkSelfPermission(context, Manifest.permission.ACCESS_FINE_LOCATION) == PackageManager.PERMISSION_GRANTED
        hasNotificationPermission = if (Build.VERSION.SDK_INT >= Build.VERSION_CODES.TIRAMISU)
            ContextCompat.checkSelfPermission(context, Manifest.permission.POST_NOTIFICATIONS) == PackageManager.PERMISSION_GRANTED else true
    }

    val locationPermissionLauncher = rememberLauncherForActivityResult(ActivityResultContracts.RequestPermission()) { hasLocationPermission = it }
    val notificationPermissionLauncher = rememberLauncherForActivityResult(ActivityResultContracts.RequestPermission()) { hasNotificationPermission = it }

    val prefs = context.getSharedPreferences("app_settings", Context.MODE_PRIVATE)
    var routeSmoothingEnabled by remember { mutableStateOf(prefs.getBoolean("route_smoothing", true)) }

    var isTopoMap by remember { mutableStateOf(prefs.getBoolean("topo_map", false)) }

    // Live kcal (prikazano med sledenjem)
    val liveCalories = remember(elapsedSeconds, avgSpeed, elevationGain, selectedActivity, actualWeightKg) {
        calculateCaloriesMet(selectedActivity, elapsedSeconds, actualWeightKg, elevationGain, avgSpeed * 3.6f)
    }

    LaunchedEffect(locationPoints) {
        mapView?.let { map ->
            routePolyline?.let { map.overlays.remove(it) }
            if (locationPoints.isNotEmpty()) {
                val polyline = Polyline(map).apply {
                    outlinePaint.color = android.graphics.Color.rgb(33, 150, 243)
                    outlinePaint.strokeWidth = 12f
                    outlinePaint.strokeCap = android.graphics.Paint.Cap.ROUND
                    outlinePaint.isAntiAlias = true
                    setPoints(locationPoints.map { GeoPoint(it.latitude, it.longitude) })
                }
                map.overlays.add(polyline); routePolyline = polyline

                if (isMapFollowingTarget) {
                    map.controller.animateTo(GeoPoint(locationPoints.last().latitude, locationPoints.last().longitude))
                }

                if (map.zoomLevelDouble < 16.0) map.controller.setZoom(17.0)
                map.invalidate()
            }
        }
    }

    val onMapTouch = {
        if (isMapFollowingTarget) isMapFollowingTarget = false
    }

    Box(Modifier.fillMaxSize().background(MaterialTheme.colorScheme.background)) {
        // Mapa
        AndroidView(
            factory = { ctx ->
                MapView(ctx).apply {
                    setTileSource(if (isTopoMap) TileSourceFactory.OpenTopo else TileSourceFactory.MAPNIK)
                    setMultiTouchControls(true); controller.setZoom(17.0)
                    val overlay = MyLocationNewOverlay(GpsMyLocationProvider(ctx), this).apply {
                        enableMyLocation(); enableFollowLocation(); setDrawAccuracyEnabled(true)
                    }
                    overlays.add(overlay); myLocationOverlay = overlay
                    controller.setCenter(GeoPoint(46.0569, 14.5058))
                    overlay.runOnFirstFix { post { overlay.myLocation?.let { controller.animateTo(it) } } }
                    mapView = this

                    setOnTouchListener { v, event ->
                        if (event.action == android.view.MotionEvent.ACTION_DOWN || event.action == android.view.MotionEvent.ACTION_MOVE) {
                            onMapTouch()
                            overlay.disableFollowLocation()
                        }
                        v.performClick()
                        false
                    }
                }
            },
            modifier = Modifier.fillMaxSize(),
            update = { map ->
                map.onResume()
                val currentSource = if (isTopoMap) TileSourceFactory.OpenTopo else TileSourceFactory.MAPNIK
                if (map.tileProvider.tileSource != currentSource) {
                    map.setTileSource(currentSource)
                }

                map.overlayManager.tilesOverlay.setColorFilter(null)
            }
        )

        // Map Type Toggle (vedno na istem mestu, zgoraj desno, nad re-center)
        SmallFloatingActionButton(
            onClick = {
                isTopoMap = !isTopoMap
                prefs.edit().putBoolean("topo_map", isTopoMap).apply()
            },
            modifier = Modifier
                .align(Alignment.TopEnd)
                .padding(16.dp),
            containerColor = MaterialTheme.colorScheme.surfaceVariant,
            contentColor = MaterialTheme.colorScheme.onSurfaceVariant
        ) {
            Icon(Icons.Filled.Map, contentDescription = "Toggle Map Type")
        }

        // Re-center button (pod gumbom za tip mape)
        if (!isMapFollowingTarget) {
            SmallFloatingActionButton(
                onClick = {
                    isMapFollowingTarget = true
                    myLocationOverlay?.enableFollowLocation()
                    locationPoints.lastOrNull()?.let {
                        mapView?.controller?.animateTo(GeoPoint(it.latitude, it.longitude))
                    }
                },
                modifier = Modifier
                    .align(Alignment.TopEnd)
                    .padding(top = 72.dp, end = 16.dp),
                containerColor = MaterialTheme.colorScheme.primary,
                contentColor = MaterialTheme.colorScheme.onPrimary
            ) {
                Icon(Icons.Filled.MyLocation, contentDescription = "Re-center map")
            }
        }

        // Stats card (levo zgoraj)
        Card(
            Modifier.align(Alignment.TopStart).padding(16.dp).fillMaxWidth(0.58f),
            colors = CardDefaults.cardColors(containerColor = MaterialTheme.colorScheme.surface.copy(alpha = 0.95f)),
            shape = RoundedCornerShape(12.dp)
        ) {
            Column(Modifier.padding(12.dp), verticalArrangement = Arrangement.spacedBy(5.dp)) {
                IconButton(onClick = onBackPressed, modifier = Modifier.align(Alignment.Start)) {
                    Icon(Icons.AutoMirrored.Filled.ArrowBack, "Back", tint = MaterialTheme.colorScheme.onSurface)
                }

                // Tip aktivnosti oznaka (med sledenjem — ne gumb)
                Row(verticalAlignment = Alignment.CenterVertically) {
                    Text(
                        "${selectedActivity.emoji} ${selectedActivity.label}",
                        fontSize = 13.sp,
                        fontWeight = FontWeight.SemiBold,
                        color = MaterialTheme.colorScheme.primary
                    )
                    if (isTracking) {
                        Spacer(Modifier.width(8.dp))
                        val (gpsProfile, gpsColor) = when (selectedActivity) {
                            ActivityType.SPRINT, ActivityType.RUN -> "High accuracy" to Color(0xFF4CAF50)
                            ActivityType.CYCLING, ActivityType.SKIING, ActivityType.SNOWBOARD, ActivityType.SKATING -> "Balanced" to MaterialTheme.colorScheme.tertiary
                            ActivityType.WALK, ActivityType.HIKE, ActivityType.NORDIC -> "Battery saver" to Color(0xFF9E9E9E)
                        }
                        Surface(
                            color = gpsColor.copy(alpha = 0.1f),
                            shape = RoundedCornerShape(4.dp),
                            border = androidx.compose.foundation.BorderStroke(1.dp, gpsColor.copy(alpha = 0.5f))
                        ) {
                            Text(
                                text = "GPS: $gpsProfile",
                                fontSize = 10.sp,
                                fontWeight = FontWeight.Medium,
                                color = gpsColor,
                                modifier = Modifier.padding(horizontal = 4.dp, vertical = 2.dp)
                            )
                        }
                    }
                }

                Text("${"%.2f".format(distanceMeters / 1000.0)} km", fontSize = 18.sp, fontWeight = FontWeight.Bold, color = MaterialTheme.colorScheme.onSurface)
                Text(fmtTime(elapsedSeconds), fontSize = 16.sp, fontWeight = FontWeight.Bold, color = MaterialTheme.colorScheme.onSurface)

                if (selectedActivity.showSpeed) {
                    Text("Max: ${"%.1f".format(maxSpeed * 3.6)} km/h", fontSize = 13.sp, color = MaterialTheme.colorScheme.onSurface)
                    Text("Avg: ${"%.1f".format(avgSpeed * 3.6)} km/h", fontSize = 13.sp, color = MaterialTheme.colorScheme.onSurface)
                }
                if (selectedActivity.showPace && distanceMeters > 50) {
                    val paceMin = if (avgSpeed > 0.1f) (1000.0 / (avgSpeed * 60.0)) else 0.0
                    Text("Pace: ${paceMin.toInt()}:${"%02d".format(((paceMin - paceMin.toInt()) * 60).toInt())} /km", fontSize = 13.sp, color = MaterialTheme.colorScheme.onSurface)
                }
                if (selectedActivity.showElevation && (elevationGain > 0f || elevationLoss > 0f)) {
                    Text("↑ ${"%.0f".format(elevationGain)} m  ↓ ${"%.0f".format(elevationLoss)} m", fontSize = 13.sp, color = Color(0xFF4CAF50))
                }
                if (isTracking) {
                    Text(" $liveCalories kcal", fontSize = 13.sp, fontWeight = FontWeight.Medium, color = MaterialTheme.colorScheme.tertiary)
                    Text(
                        if (isPaused) "Paused" else "Tracking...",
                        fontSize = 12.sp,
                        color = if (isPaused) MaterialTheme.colorScheme.tertiary else Color(0xFF4CAF50),
                        fontWeight = FontWeight.Medium
                    )
                }
            }
        }

        // Controls card (spodaj)
        Card(
            Modifier.align(Alignment.BottomCenter).padding(16.dp).fillMaxWidth(),
            colors = CardDefaults.cardColors(containerColor = MaterialTheme.colorScheme.surface.copy(alpha = 0.95f)),
            shape = RoundedCornerShape(16.dp)
        ) {
            Column(Modifier.padding(horizontal = 16.dp, vertical = 12.dp)) {
                // --- Picker aktivnosti (samo ko ne sledimo) ---
                if (!isTracking && !showSummary) {
                    // Izbrani tip + gumb za spremembo
                    Row(
                        Modifier
                            .fillMaxWidth()
                            .clickable { showActivityPicker = !showActivityPicker }
                            .background(MaterialTheme.colorScheme.surfaceVariant, RoundedCornerShape(10.dp))
                            .padding(horizontal = 14.dp, vertical = 8.dp),
                        verticalAlignment = Alignment.CenterVertically
                    ) {
                        Text(
                            "${selectedActivity.emoji} ${selectedActivity.label}",
                            fontSize = 15.sp,
                            fontWeight = FontWeight.SemiBold,
                            color = MaterialTheme.colorScheme.onSurface,
                            modifier = Modifier.weight(1f)
                        )
                        Icon(Icons.Filled.ArrowDropDown, "Izberi aktivnost", tint = MaterialTheme.colorScheme.primary)
                    }

                    // Picker lista — horizontalni scroll
                    if (showActivityPicker) {
                        Spacer(Modifier.height(8.dp))
                        LazyRow(
                            horizontalArrangement = Arrangement.spacedBy(8.dp),
                            contentPadding = PaddingValues(horizontal = 2.dp)
                        ) {
                            items(items = ActivityType.entries, key = { it.name }) { type ->
                                val isSelected = type == selectedActivity
                                Surface(
                                    shape = RoundedCornerShape(20.dp),
                                    color = if (isSelected) MaterialTheme.colorScheme.primary else MaterialTheme.colorScheme.surfaceVariant,
                                    modifier = Modifier.clickable {
                                        selectedActivity = type
                                        showActivityPicker = false
                                    }
                                ) {
                                    Text(
                                        "${type.emoji} ${type.label}",
                                        modifier = Modifier.padding(horizontal = 12.dp, vertical = 8.dp),
                                        fontSize = 13.sp,
                                        fontWeight = if (isSelected) FontWeight.Bold else FontWeight.Normal,
                                        color = if (isSelected) Color.White else MaterialTheme.colorScheme.onSurface
                                    )
                                }
                            }
                        }
                        Spacer(Modifier.height(8.dp))
                    }
                    Spacer(Modifier.height(8.dp))
                }

                // Gumbi
                Row(
                    Modifier.fillMaxWidth(),
                    horizontalArrangement = Arrangement.spacedBy(12.dp),
                    verticalAlignment = Alignment.CenterVertically
                ) {
                    when {
                        !isTracking && !showSummary -> Button(
                            onClick = {
                                when {
                                    !hasLocationPermission -> locationPermissionLauncher.launch(Manifest.permission.ACCESS_FINE_LOCATION)
                                    !hasNotificationPermission && Build.VERSION.SDK_INT >= Build.VERSION_CODES.TIRAMISU ->
                                        notificationPermissionLauncher.launch(Manifest.permission.POST_NOTIFICATIONS)
                                    else -> {
                                        val locationManager = context.getSystemService(Context.LOCATION_SERVICE) as LocationManager
                                        if (!locationManager.isProviderEnabled(LocationManager.GPS_PROVIDER)) {
                                            showGpsDialog = true
                                        } else {
                                            showActivityPicker = false
                                            context.startForegroundService(Intent(context, RunTrackingService::class.java).apply { action = RunTrackingService.ACTION_START })
                                        }
                                    }
                                }
                            },
                            modifier = Modifier.weight(1f).height(56.dp),
                            colors = ButtonDefaults.buttonColors(containerColor = Color(0xFF4CAF50)),
                            shape = RoundedCornerShape(12.dp)
                        ) {
                            Icon(Icons.Filled.PlayArrow, null)
                            Spacer(Modifier.width(8.dp))
                            Text("Start ${selectedActivity.label}", fontSize = 16.sp, fontWeight = FontWeight.Bold)
                        }

                        isTracking -> {
                            Button(
                                onClick = { context.startService(Intent(context, RunTrackingService::class.java).apply { action = if (isPaused) RunTrackingService.ACTION_RESUME else RunTrackingService.ACTION_PAUSE }) },
                                modifier = Modifier.weight(1f).height(56.dp),
                                colors = ButtonDefaults.buttonColors(containerColor = if (isPaused) Color(0xFF4CAF50) else MaterialTheme.colorScheme.tertiary),
                                shape = RoundedCornerShape(12.dp)
                            ) { Icon(if (isPaused) Icons.Filled.PlayArrow else Icons.Filled.Pause, null); Spacer(Modifier.width(8.dp)); Text(if (isPaused) "Resume" else "Pause", fontSize = 16.sp, fontWeight = FontWeight.Bold) }

                            Button(
                                onClick = {
                                    if (distanceMeters < 20.0) {
                                        context.startService(Intent(context, RunTrackingService::class.java).apply { action = RunTrackingService.ACTION_PAUSE })
                                        showDiscardDialog = true
                                        return@Button
                                    }

                                    finalDistance = distanceMeters; finalTime = elapsedSeconds
                                    finalMaxSpeed = maxSpeed; finalAvgSpeed = avgSpeed
                                    finalElevationGain = elevationGain; finalElevationLoss = elevationLoss

                                    // ADDED: Samodejni predlog aktivnosti na podlagi hitrosti
                                    val currentAvgKmh = avgSpeed * 3.6f
                                    if (finalDistance > 100 && currentAvgKmh > 0) {
                                        if (selectedActivity == ActivityType.RUN && currentAvgKmh < 6.0f) {
                                            selectedActivity = ActivityType.WALK
                                            com.example.myapplication.utils.AppToast.showSuccess(context, "Activity changed to Walk based on speed (${String.format(java.util.Locale.US, "%.1f", currentAvgKmh)} km/h)")
                                        } else if (selectedActivity == ActivityType.WALK && currentAvgKmh > 7.5f) {
                                            selectedActivity = ActivityType.RUN
                                            com.example.myapplication.utils.AppToast.showSuccess(context, "Activity changed to Run based on speed (${String.format(java.util.Locale.US, "%.1f", currentAvgKmh)} km/h)")
                                        }
                                    }

                                    context.startService(Intent(context, RunTrackingService::class.java).apply { action = RunTrackingService.ACTION_STOP })

                                    showSummary = true
                                },
                                modifier = Modifier.weight(1f).height(56.dp),
                                colors = ButtonDefaults.buttonColors(containerColor = Color(0xFFF44336)),
                                shape = RoundedCornerShape(12.dp)
                            ) { Icon(Icons.Filled.Stop, null); Spacer(Modifier.width(8.dp)); Text("Stop", fontSize = 16.sp, fontWeight = FontWeight.Bold) }
                        }

                        showSummary -> Spacer(Modifier.height(56.dp))
                    }
                }
            }
        }

        // Summary overlay
        if (showSummary) {
            val xpEarned = calculateXP(selectedActivity, finalDistance, finalTime)

            Box(Modifier.fillMaxSize().background(Color.Black.copy(alpha = 0.6f))) {
                Card(
                    Modifier.align(Alignment.Center).fillMaxWidth(0.88f),
                    colors = CardDefaults.cardColors(containerColor = MaterialTheme.colorScheme.surface),
                    shape = RoundedCornerShape(20.dp)
                ) {
                    Column(
                        Modifier.padding(24.dp).fillMaxWidth(),
                        horizontalAlignment = Alignment.CenterHorizontally,
                        verticalArrangement = Arrangement.spacedBy(10.dp)
                    ) {
                        Text(
                            "${selectedActivity.emoji} ${selectedActivity.label} Complete!",
                            fontSize = 22.sp, fontWeight = FontWeight.Bold,
                            color = MaterialTheme.colorScheme.primary
                        )
                        HorizontalDivider()

                        SummaryRow(" Distance", "${"%.2f".format(finalDistance / 1000.0)} km")
                        SummaryRow("⏱️ Duration", fmtTime(finalTime))

                        if (selectedActivity.showSpeed) {
                            SummaryRow("⚡ Max speed", "${"%.1f".format(finalMaxSpeed * 3.6)} km/h")
                            SummaryRow(" Avg speed", "${"%.1f".format(finalAvgSpeed * 3.6)} km/h")
                        }
                        if (selectedActivity.showPace && finalDistance > 50) {
                            val p = (finalTime / 60.0) / (finalDistance / 1000.0)
                            SummaryRow(" Pace", "${p.toInt()}:${"%02d".format(((p - p.toInt()) * 60).toInt())} /km")
                        }
                        if (selectedActivity.showElevation && (finalElevationGain > 0f || finalElevationLoss > 0f)) {
                            SummaryRow("⛰️ Ascent", "${"%.0f".format(finalElevationGain)} m")
                            SummaryRow("↘️ Descent", "${"%.0f".format(finalElevationLoss)} m")
                        }

                        SummaryRow(" XP Earned", "$xpEarned XP", highlight = true)

                        HorizontalDivider()
                        Row(verticalAlignment = Alignment.CenterVertically) {
                            Checkbox(
                                checked = routeSmoothingEnabled,
                                onCheckedChange = {
                                    routeSmoothingEnabled = it
                                    prefs.edit().putBoolean("route_smoothing", it).apply()
                                }
                            )
                            Text("Route smoothing (Snap-to-road)", fontSize = 14.sp)
                        }

                        Button(
                            onClick = {
                                if (isSavingActivity) return@Button
                                isSavingActivity = true
                                val sessionId = java.util.UUID.randomUUID().toString()
                                val avgKmh = finalAvgSpeed * 3.6f
                                val calories = calculateCaloriesMet(selectedActivity, finalTime, actualWeightKg, finalElevationGain, avgKmh)

                                scope.launch(Dispatchers.IO) {
                                    val mappedLocationPoints = locationPoints.map { loc ->
                                        com.example.myapplication.data.LocationPoint(
                                            latitude = loc.latitude,
                                            longitude = loc.longitude,
                                            altitude = loc.altitude,
                                            speed = loc.speed,
                                            accuracy = loc.accuracy,
                                            timestamp = loc.time
                                        )
                                    }

                                    var finalLocationPoints = mappedLocationPoints
                                    var successfullySmoothed = false
                                    if (routeSmoothingEnabled) {
                                        val isWalkingProfile = selectedActivity == ActivityType.RUN || selectedActivity == ActivityType.WALK || selectedActivity == ActivityType.HIKE
                                        // Opravimo glajenje poti za vgrajene tipe
                                        if (isWalkingProfile || selectedActivity == ActivityType.CYCLING || selectedActivity == ActivityType.SPRINT) {
                                            finalLocationPoints = com.example.myapplication.map.MapboxMapMatcher.matchRoute(mappedLocationPoints, isWalkingProfile)
                                            if (finalLocationPoints !== mappedLocationPoints) {
                                                successfullySmoothed = true
                                            }
                                        }
                                    }

                                    if (uid != null) {
                                        val avgSpeedMps = if (finalTime > 0) (finalDistance / finalTime).toFloat() else 0f
                                        val runMap = hashMapOf<String, Any>(
                                            "id" to sessionId, "userId" to uid,
                                            "startTime" to (System.currentTimeMillis() - finalTime * 1000L),
                                            "endTime" to System.currentTimeMillis(),
                                            "durationSeconds" to finalTime.toInt(),
                                            "distanceMeters" to finalDistance,
                                            "maxSpeedMps" to finalMaxSpeed,
                                            "avgSpeedMps" to avgSpeedMps,
                                            "caloriesKcal" to calories,
                                            "elevationGainM" to finalElevationGain,
                                            "elevationLossM" to finalElevationLoss,
                                            "activityType" to selectedActivity.name,
                                            "createdAt" to System.currentTimeMillis(),
                                            "polylinePoints" to emptyList<Any>(),
                                            "isSmoothed" to successfullySmoothed
                                        )
                                        Firebase.firestore
                                            .collection("users").document(uid)
                                            .collection("runSessions").document(sessionId)
                                            .set(runMap)

                                        val email = com.google.firebase.auth.FirebaseAuth.getInstance().currentUser?.email
                                        if (email != null) {
                                            val shareActSnap = Firebase.firestore.collection("users").document(uid).get().await()
                                            val shareAct = shareActSnap.getBoolean("share_activities") ?: false
                                            if (shareAct && finalLocationPoints.isNotEmpty()) {
                                                val rawPts = finalLocationPoints.map { Pair(it.latitude, it.longitude) }
                                                val compressed = com.example.myapplication.utils.RouteCompressor.compress(rawPts)
                                                val routeList = compressed.map { (lat, lng) -> mapOf("lat" to lat, "lng" to lng) }
                                                val pubMap = hashMapOf<String, Any>(
                                                    "activityType" to selectedActivity.name,
                                                    "distanceMeters" to finalDistance,
                                                    "elevationGainM" to finalElevationGain,
                                                    "elevationLossM" to finalElevationLoss,
                                                    "avgSpeedMps" to avgSpeedMps,
                                                    "maxSpeedMps" to finalMaxSpeed,
                                                    "startTime" to (System.currentTimeMillis() - finalTime * 1000L),
                                                    "routePoints" to routeList
                                                )
                                                Firebase.firestore
                                                    .collection("users").document(uid)
                                                    .collection("publicActivities").document(sessionId)
                                                    .set(pubMap)
                                            }
                                        }
                                    }

                                    // VEDNO shranimo originalne (raw) točke, da ohranimo pravilen hitrostni graf in meritve!
                                    if (mappedLocationPoints.isNotEmpty()) {
                                        com.example.myapplication.persistence.RunRouteStore.saveRoute(context, sessionId, mappedLocationPoints)
                                    }
                                    // Če je glajenje uspelo, shranimo dodaten file samo za risanje čudovite poti na mapi
                                    if (successfullySmoothed && finalLocationPoints.isNotEmpty()) {
                                        com.example.myapplication.persistence.RunRouteStore.saveRoute(context, sessionId + "_smoothed", finalLocationPoints)
                                    }

                                    val xp = calculateXP(selectedActivity, finalDistance, finalTime)
                                    val runEmail = com.google.firebase.auth.FirebaseAuth.getInstance().currentUser?.email
                                    if (runEmail != null) {
                                        com.example.myapplication.persistence.AchievementStore.awardXP(
                                            context, runEmail, xp,
                                            com.example.myapplication.data.XPSource.RUN_COMPLETED,
                                            "Completed ${selectedActivity.label}: ${finalDistance.toInt()}m"
                                        )

                                        val app = context.applicationContext as android.app.Application
                                        val bodyVm = androidx.lifecycle.ViewModelProvider.AndroidViewModelFactory.getInstance(app)
                                            .create(com.example.myapplication.viewmodels.BodyModuleHomeViewModel::class.java)
                                        val uiState = bodyVm.ui.value
                                        val currentDay = uiState.planDay
                                        if (!uiState.isWorkoutDoneToday && !uiState.todayIsRest && finalDistance > 1000) {
                                            bodyVm.completeWorkoutSession(
                                                isExtraWorkout = false,
                                                totalKcal = calories,
                                                totalTimeMin = finalTime / 60.0
                                            )
                                            withContext(Dispatchers.Main) {
                                                com.example.myapplication.utils.AppToast.showSuccess(context, "Workout Day $currentDay Complete! +$xp XP!")
                                            }
                                        } else {
                                            withContext(Dispatchers.Main) {
                                                com.example.myapplication.utils.AppToast.showSuccess(context, "+$xp XP!")
                                            }
                                        }
                                    }
                                    withContext(Dispatchers.Main) {
                                        showSummary = false; onBackPressed()
                                    }
                                }
                            },
                            modifier = Modifier.fillMaxWidth(0.8f).height(50.dp),
                            enabled = !isSavingActivity,
                            colors = ButtonDefaults.buttonColors(containerColor = MaterialTheme.colorScheme.primary),
                            shape = RoundedCornerShape(12.dp)
                        ) {
                            if (isSavingActivity) {
                                CircularProgressIndicator(modifier = Modifier.size(24.dp), color = MaterialTheme.colorScheme.onPrimary)
                            } else {
                                Text("Done", fontSize = 18.sp, fontWeight = FontWeight.Bold)
                            }
                        }
                    }
                }
            }
        }
    }

    if (showGpsDialog) {
        AlertDialog(
            onDismissRequest = { showGpsDialog = false },
            title = { Text("GPS ni vklopljen", fontWeight = FontWeight.Bold) },
            text = { Text("Za sledenje aktivnosti potrebuješ vklopljeno lokacijo (GPS). Prosimo vklopi lokacijo v nastavitvah naprave.") },
            confirmButton = {
                TextButton(onClick = {
                    showGpsDialog = false
                    context.startActivity(Intent(Settings.ACTION_LOCATION_SOURCE_SETTINGS))
                }) { Text("Odpri nastavitve") }
            },
            dismissButton = { TextButton(onClick = { showGpsDialog = false }) { Text("Prekliči") } }
        )
    }

    if (showDiscardDialog) {
        AlertDialog(
            onDismissRequest = { showDiscardDialog = false },
            title = { Text("Activity Too Short", fontWeight = FontWeight.Bold) },
            text = { Text("You have recorded less than 20m. Your activity will not be saved if you finish now. Do you want to discard it?") },
            confirmButton = {
                TextButton(onClick = {
                    showDiscardDialog = false
                    context.startService(Intent(context, RunTrackingService::class.java).apply { action = RunTrackingService.ACTION_STOP })
                    onBackPressed()
                }) { Text("Discard", color = MaterialTheme.colorScheme.error) }
            },
            dismissButton = {
                TextButton(onClick = { showDiscardDialog = false }) { Text("Cancel") }
            }
        )
    }
}

@Composable
private fun SummaryRow(label: String, value: String, highlight: Boolean = false) {
    Row(
        Modifier.fillMaxWidth(),
        horizontalArrangement = Arrangement.SpaceBetween,
        verticalAlignment = Alignment.CenterVertically
    ) {
        Text(label, fontSize = 15.sp, color = MaterialTheme.colorScheme.onSurfaceVariant)
        Text(
            value,
            fontSize = if (highlight) 17.sp else 15.sp,
            fontWeight = if (highlight) FontWeight.Bold else FontWeight.Medium,
            color = if (highlight) MaterialTheme.colorScheme.tertiary else MaterialTheme.colorScheme.onSurface
        )
    }
}

private fun fmtTime(s: Long) = if (s >= 3600) "%d:%02d:%02d".format(s / 3600, (s % 3600) / 60, s % 60) else "%02d:%02d".format(s / 60, s % 60)

package com.example.myapplication.data.repository

import android.util.Log
import com.example.myapplication.data.store.FirestoreHelper
import com.example.myapplication.domain.model.BodyMeasurementEntry
import com.example.myapplication.domain.repository.BodyMeasurementsRepository
import com.google.firebase.firestore.Query
import com.google.firebase.firestore.SetOptions
import kotlinx.coroutines.channels.awaitClose
import kotlinx.coroutines.flow.Flow
import kotlinx.coroutines.flow.callbackFlow
import kotlinx.coroutines.tasks.await

/**
 * Faza 30.6 — Edina Firestore implementacija BodyMeasurementsRepository.
 *
 * Subcollection schema:
 *   users/{userId}/measurements_history/{YYYY-MM-DD}
 *     shoulderCm: Double
 *     waistCm:    Double
 *     hipCm:      Double
 *     heightCm:   Double
 *     timestamp:  Long   ← epoch ms ob zadnjem shranjevanju tega dne
 *
 * Faza 30.8 — Document ID = datum (YYYY-MM-DD): upsert semantika, en vnos na dan.
 * Faza 30.9 — dateId prihaja iz domene (UseCase), ne iz sistemske ure naprave.
 *   → Repozitorij je popolnoma determinističen in testabilen.
 * Faza 31.0 — batch.set z SetOptions.merge(): drugi moduli (teža, body fat) varno
 *   pišejo v isti dnevni dokument brez tveganja brisanja obstoječih polj.
 *   → Batch write zagotavlja atomarnost (profil + history sta vedno sinhronizirana).
 */
class FirestoreBodyMeasurementsRepository : BodyMeasurementsRepository {

    companion object {
        private const val TAG = "BodyMeasurementsRepo"
        private const val HISTORY_COLLECTION = "measurements_history"
    }

    /**
     * Batch write (atomarno):
     *   a) Posodobi shoulderCm / waistCm / hipCm v root user dokumentu — za GoldenRatio izračun
     *   b) Doda/posodobi dokument v measurements_history z ID = [dateId] (upsert)
     *
     * Faza 30.9 — [dateId] generira UseCase, ne ta razred. Repozitorij je determinističen.
     */
    override suspend fun saveMeasurements(
        dateId: String,
        shoulderCm: Double,
        waistCm: Double,
        hipCm: Double,
        heightCm: Double
    ): Result<Unit> {
        return try {
            val db = FirestoreHelper.getDb()
            val userRef = FirestoreHelper.getCurrentUserDocRef()
            val timestamp = System.currentTimeMillis()

            val batch = db.batch()

            // a) Posodobi trenutne vrednosti v profilu (merge — ne prepiše ostalih polj)
            val profileUpdate = mapOf(
                "shoulderCm" to shoulderCm,
                "waistCm"    to waistCm,
                "hipCm"      to hipCm
            )
            batch.update(userRef, profileUpdate)

            // b) Novi/posodobljeni dokument v subcollection — ID = datum (upsert semantika)
            val historyRef = userRef
                .collection(HISTORY_COLLECTION)
                .document(dateId)

            val historyDoc = mapOf(
                "shoulderCm" to shoulderCm,
                "waistCm"    to waistCm,
                "hipCm"      to hipCm,
                "heightCm"   to heightCm,
                "timestamp"  to timestamp
            )
            // Faza 31.0 — SetOptions.merge(): ne izbriše polj, ki jih ta klic ne pozna
            // (npr. "weightKg", "bodyFatPct" ki bi jih dodali drugi moduli v prihodnosti)
            batch.set(historyRef, historyDoc, SetOptions.merge())

            batch.commit().await()

            Log.d(TAG, "✅ Batch write uspel: meritve + history (dateId=$dateId, ts=$timestamp)")
            Result.success(Unit)
        } catch (e: Exception) {
            Log.e(TAG, "❌ Batch write spodletel: ${e.message}")
            Result.failure(e)
        }
    }

    /**
     * Reaktivni tok celotne zgodovine, urejene ASC po timestamp.
     * callbackFlow — samodejno ugasne ob prekinitvi naročnine.
     */
    override fun observeMeasurementsHistory(): Flow<List<BodyMeasurementEntry>> = callbackFlow {
        val listener = try {
            val userRef = FirestoreHelper.getCurrentUserDocRef()
            userRef.collection(HISTORY_COLLECTION)
                .orderBy("timestamp", Query.Direction.ASCENDING)
                .addSnapshotListener { snap, error ->
                    if (error != null) {
                        Log.e(TAG, "Listener error: ${error.message}")
                        return@addSnapshotListener
                    }
                    val entries = snap?.documents?.mapNotNull { doc ->
                        try {
                            BodyMeasurementEntry(
                                shoulderCm = (doc.getDouble("shoulderCm") ?: 0.0),
                                waistCm    = (doc.getDouble("waistCm")    ?: 0.0),
                                hipCm      = (doc.getDouble("hipCm")      ?: 0.0),
                                heightCm   = (doc.getDouble("heightCm")   ?: 0.0),
                                timestamp  = (doc.getLong("timestamp")    ?: 0L)
                            )
                        } catch (e: Exception) {
                            Log.e(TAG, "Error parsing history doc ${doc.id}: ${e.message}")
                            null
                        }
                    } ?: emptyList()
                    trySend(entries)
                }
        } catch (e: Exception) {
            Log.e(TAG, "Error starting history listener: ${e.message}")
            trySend(emptyList())
            null
        }

        awaitClose { listener?.remove() }
    }
}

package com.example.myapplication.data.repository
import android.util.Log import com.example.myapplication.data.store.FirestoreHelper import com.example.myapplication.domain.model.BodyMeasurementEntry import com.example.myapplication.domain.repository.BodyMeasurementsRepository import com.google.firebase.firestore.Query import com.google.firebase.firestore.SetOptions import kotlinx.coroutines.Dispatchers import kotlinx.coroutines.NonCancellable import kotlinx.coroutines.channels.awaitClose import kotlinx.coroutines.flow.Flow import kotlinx.coroutines.flow.callbackFlow import kotlinx.coroutines.tasks.await import kotlinx.coroutines.withContext
/** * Faza 30.6 — Edina Firestore implementacija BodyMeasurementsRepository. * * Subcollection schema: * users/{userId}/measurements_history/{YYYY-MM-DD} * shoulderCm: Double * waistCm: Double * hipCm: Double * heightCm: Double * timestamp: Long ← epoch ms ob zadnjem shranjevanju tega dne * * Faza 30.8 — Document ID = datum (YYYY-MM-DD): upsert semantika, en vnos na dan. * Faza 30.9 — dateId prihaja iz domene (UseCase), ne iz sistemske ure naprave. * → Repozitorij je popolnoma determinističen in testabilen. * Faza 31.0 — batch.set z SetOptions.merge(): drugi moduli (teža, body fat) varno * pišejo v isti dnevni dokument brez tveganja brisanja obstoječih polj. * → Batch write zagotavlja atomarnost (profil + history sta vedno sinhronizirana). */ class FirestoreBodyMeasurementsRepository : BodyMeasurementsRepository {
companion object { private const val TAG = "BodyMeasurementsRepo" private const val HISTORY_COLLECTION = "measurements_history" }
/** * Batch write (atomarno): * a) Posodobi shoulderCm / waistCm / hipCm v root user dokumentu — za GoldenRatio izračun * b) Doda/posodobi dokument v measurements_history z ID = [dateId] (upsert) * * Faza 30.9 — [dateId] generira UseCase, ne ta razred. Repozitorij je determinističen. * * [NonCancellable]: Firestore batch.commit() mora v celoti zaključiti, tudi če * klic­čev viewModelScope odpove (navigacija stran). Delni Firestore batch == korupcija * (profil posodobljen, history ne — ali obratno). NonCancellable zagotavlja atomarnost. */ override suspend fun saveMeasurements( dateId: String, shoulderCm: Double, waistCm: Double, hipCm: Double, heightCm: Double ): Result<Unit> = withContext(Dispatchers.IO + NonCancellable) { try { val db = FirestoreHelper.getDb() val userRef = FirestoreHelper.getCurrentUserDocRef() val timestamp = System.currentTimeMillis()
val batch = db.batch()
// a) Posodobi trenutne vrednosti v profilu (merge — ne prepiše ostalih polj) val profileUpdate = mapOf( "shoulderCm" to shoulderCm, "waistCm" to waistCm, "hipCm" to hipCm ) batch.update(userRef, profileUpdate)
// b) Novi/posodobljeni dokument v subcollection — ID = datum (upsert semantika) val historyRef = userRef .collection(HISTORY_COLLECTION) .document(dateId)
val historyDoc = mapOf( "shoulderCm" to shoulderCm, "waistCm" to waistCm, "hipCm" to hipCm, "heightCm" to heightCm, "timestamp" to timestamp ) // Faza 31.0 — SetOptions.merge(): ne izbriše polj, ki jih ta klic ne pozna batch.set(historyRef, historyDoc, SetOptions.merge())
batch.commit().await()
Log.d(TAG, "✅ Batch write uspel: meritve + history (dateId=$dateId, ts=$timestamp)") Result.success(Unit) } catch (e: Exception) { Log.e(TAG, "❌ Batch write spodletel: ${e.message}") Result.failure(e) } }
/** * Reaktivni tok celotne zgodovine, urejene ASC po timestamp. * callbackFlow — samodejno ugasne ob prekinitvi naročnine. */ override fun observeMeasurementsHistory(): Flow<List<BodyMeasurementEntry>> = callbackFlow { val listener = try { val userRef = FirestoreHelper.getCurrentUserDocRef() userRef.collection(HISTORY_COLLECTION) .orderBy("timestamp", Query.Direction.ASCENDING) .addSnapshotListener { snap, error -> if (error != null) { Log.e(TAG, "Listener error: ${error.message}") return@addSnapshotListener } val entries = snap?.documents?.mapNotNull { doc -> try { BodyMeasurementEntry( shoulderCm = (doc.getDouble("shoulderCm") ?: 0.0), waistCm = (doc.getDouble("waistCm") ?: 0.0), hipCm = (doc.getDouble("hipCm") ?: 0.0), heightCm = (doc.getDouble("heightCm") ?: 0.0), timestamp = (doc.getLong("timestamp") ?: 0L) ) } catch (e: Exception) { Log.e(TAG, "Error parsing history doc ${doc.id}: ${e.message}") null } } ?: emptyList() trySend(entries) } } catch (e: Exception) { Log.e(TAG, "Error starting history listener: ${e.message}") trySend(emptyList()) null }
awaitClose { listener?.remove() } } }

package com.example.myapplication.data.repository

import android.util.Log
import com.example.myapplication.domain.model.ActivityType
import com.example.myapplication.domain.model.LocationPoint
import com.example.myapplication.domain.model.RunSession
import com.example.myapplication.domain.repository.WorkoutRepository
import com.example.myapplication.data.store.FirestoreHelper
import com.google.firebase.firestore.DocumentReference
import com.google.firebase.firestore.DocumentSnapshot
import com.google.firebase.firestore.Query
import kotlinx.coroutines.tasks.await

class FirestoreWorkoutRepository : WorkoutRepository {

    override suspend fun getWeeklyDoneCount(email: String, startEpochSeconds: Long): Int {
        val startEpochMs = startEpochSeconds * 1000L
        return try {
            val ref = FirestoreHelper.getCurrentUserDocRef()
            val querySnapshot = ref.collection("workoutSessions")
                .whereGreaterThanOrEqualTo("timestamp", startEpochMs)
                .get()
                .await()
            querySnapshot.documents.count { doc ->
                (doc.getString("type") ?: "regular") == "regular"
            }
        } catch (e: Exception) {
            -1
        }
    }

    override suspend fun saveWorkoutSession(email: String, workoutDoc: Map<String, Any>): Boolean {
        return try {
            val ref = FirestoreHelper.getCurrentUserDocRef()
            ref.collection("workoutSessions").add(workoutDoc).await()
            true
        } catch (e: Exception) {
            false
        }
    }

    /**
     * Naloži GPS točke za sesijo — poskusi v vrstnem redu:
     *  1. Sub-kolekcija `gps_points` (nova naprava / nova pot)
     *  2. Sub-kolekcija `points` (po migracijskem načrtu GPS_POINTS_MIGRATION_PLAN.md)
     *  3. Inline `polylinePoints` array v dokumentu (stari format, backwards compat)
     *
     * Pot: users/{uid}/runSessions/{docId}/gps_points  ali  .../points
     */
    private suspend fun loadGpsPoints(
        sessionRef: DocumentReference,
        inlinePoints: List<LocationPoint>
    ): List<LocationPoint> {
        // 1. Poskusi gps_points subcollection
        try {
            val gpsSnap = sessionRef.collection("gps_points")
                .orderBy("chunkIndex")
                .get().await()
            if (!gpsSnap.isEmpty) {
                val pts = gpsSnap.documents.flatMap { doc ->
                    @Suppress("UNCHECKED_CAST")
                    val rawPts = doc.get("pts") as? List<Map<String, Any>> ?: emptyList()
                    rawPts.mapNotNull { pt ->
                        try {
                            LocationPoint(
                                latitude = (pt["lat"] as? Number)?.toDouble()
                                    ?: return@mapNotNull null,
                                longitude = (pt["lng"] as? Number)?.toDouble()
                                    ?: return@mapNotNull null,
                                altitude = (pt["alt"] as? Number)?.toDouble() ?: 0.0,
                                speed = (pt["spd"] as? Number)?.toFloat() ?: 0f,
                                accuracy = 0f,
                                timestamp = (pt["ts"] as? Number)?.toLong() ?: 0L
                            )
                        } catch (e: Exception) {
                            Log.e("WorkoutRepo", "❌ gps_points točka parse napaka @ ${sessionRef.path}: ${e.message}", e)
                            null
                        }
                    }
                }
                if (pts.isNotEmpty()) {
                    Log.d("WorkoutRepo", "GPS: ${pts.size} točk iz gps_points @ ${sessionRef.path}")
                    return pts
                } else {
                    Log.w("WorkoutRepo", "⚠️ gps_points subcollection obstaja ampak je prazna @ ${sessionRef.path}")
                }
            } else {
                Log.d("WorkoutRepo", "GPS: gps_points subcollection prazna @ ${sessionRef.path}")
            }
        } catch (e: Exception) {
            Log.e("WorkoutRepo", "❌ gps_points fetch napaka @ ${sessionRef.path}: ${e.message}", e)
        }

        // 2. Poskusi `points` subcollection (GPS_POINTS_MIGRATION_PLAN format)
        try {
            val pointsSnap = sessionRef.collection("points")
                .orderBy("chunkIndex")
                .get().await()
            if (!pointsSnap.isEmpty) {
                val pts = pointsSnap.documents.flatMap { doc ->
                    @Suppress("UNCHECKED_CAST")
                    val rawPts = doc.get("pts") as? List<Map<String, Any>> ?: emptyList()
                    rawPts.mapNotNull { pt ->
                        try {
                            LocationPoint(
                                latitude = (pt["lat"] as? Number)?.toDouble()
                                    ?: return@mapNotNull null,
                                longitude = (pt["lng"] as? Number)?.toDouble()
                                    ?: return@mapNotNull null,
                                altitude = (pt["alt"] as? Number)?.toDouble() ?: 0.0,
                                speed = 0f, accuracy = 0f,
                                timestamp = (pt["ts"] as? Number)?.toLong() ?: 0L
                            )
                        } catch (e: Exception) {
                            Log.e("WorkoutRepo", "❌ points točka parse napaka @ ${sessionRef.path}: ${e.message}", e)
                            null
                        }
                    }
                }
                if (pts.isNotEmpty()) {
                    Log.d("WorkoutRepo", "GPS: ${pts.size} točk iz points sub-kolekcije @ ${sessionRef.path}")
                    return pts
                } else {
                    Log.w("WorkoutRepo", "⚠️ points subcollection obstaja ampak je prazna @ ${sessionRef.path}")
                }
            } else {
                Log.d("WorkoutRepo", "GPS: points subcollection prazna @ ${sessionRef.path}")
            }
        } catch (e: Exception) {
            Log.e("WorkoutRepo", "❌ points subcollection fetch napaka @ ${sessionRef.path}: ${e.message}", e)
        }

        // 3. Fallback: inline polylinePoints (stari format)
        Log.d("WorkoutRepo", "GPS fallback: inline polylinePoints (${inlinePoints.size} točk) @ ${sessionRef.path}")
        return inlinePoints
    }

    override suspend fun getRunSessions(userId: String, startAfterDoc: Any?, limit: Int): Pair<List<RunSession>, Any?> {
        return try {
            val userRef = FirestoreHelper.getCurrentUserDocRef()
            var query = userRef
                .collection("runSessions")
                .orderBy("createdAt", Query.Direction.DESCENDING)
                .limit(limit.toLong())

            if (startAfterDoc is DocumentSnapshot) {
                query = query.startAfter(startAfterDoc)
            }

            val snapshot = query.get().await()
            val sessions = snapshot.documents.mapNotNull { doc ->
                try {
                    val data = doc.data ?: return@mapNotNull null
                    // Preberi inline polylinePoints (fallback za stare dokumente)
                    val inlinePoints = try {
                        @Suppress("UNCHECKED_CAST")
                        val rawPts = data["polylinePoints"] as? List<Map<String, Any>>
                        rawPts?.mapNotNull { pt ->
                            try {
                                LocationPoint(
                                    latitude = (pt["latitude"] as? Number
                                        ?: pt["lat"] as? Number)?.toDouble()
                                        ?: return@mapNotNull null,
                                    longitude = (pt["longitude"] as? Number
                                        ?: pt["lng"] as? Number)?.toDouble()
                                        ?: return@mapNotNull null,
                                    altitude = (pt["altitude"] as? Number
                                        ?: pt["alt"] as? Number)?.toDouble() ?: 0.0,
                                    speed = (pt["speed"] as? Number
                                        ?: pt["spd"] as? Number)?.toFloat() ?: 0f,
                                    accuracy = (pt["accuracy"] as? Number
                                        ?: pt["acc"] as? Number)?.toFloat() ?: 0f,
                                    timestamp = (pt["timestamp"] as? Number
                                        ?: pt["ts"] as? Number)?.toLong() ?: 0L
                                )
                            } catch (_: Exception) { null }
                        } ?: emptyList()
                    } catch (_: Exception) { emptyList() }

                    // ── GPS Firestore Data Link ───────────────────────────────────────────
                    // Sub-kolekcijo beremo SAMO ko inline točk ni (npr. drugi telefon, stari zapis).
                    // FIX N+1: prej je RUNNING/CYCLING/WALKING vedno sprožil 2 dodatna get() klica
                    // (gps_points + points subcollection) — tudi ko so bile inline točke prisotne.
                    // Rezultat: 15 tekov × 2 klica = 30 nepotrebnih roundtrip-ov (~2-3s zamude).
                    val activityTypeStr = data["activityType"] as? String ?: ""
                    val needsSubFetch = inlinePoints.isEmpty()
                    val finalPoints = if (needsSubFetch) {
                        loadGpsPoints(doc.reference, inlinePoints)
                    } else inlinePoints
                    // ──────────────────────────────────────────────────────────────────────

                    RunSession(
                        id = data["id"] as? String ?: "",
                        userId = data["userId"] as? String ?: "",
                        startTime = (data["startTime"] as? Number)?.toLong() ?: 0L,
                        endTime = (data["endTime"] as? Number)?.toLong() ?: 0L,
                        durationSeconds = (data["durationSeconds"] as? Number)?.toInt() ?: 0,
                        distanceMeters = (data["distanceMeters"] as? Number)?.toDouble() ?: 0.0,
                        maxSpeedMps = (data["maxSpeedMps"] as? Number)?.toFloat() ?: 0.0f,
                        avgSpeedMps = (data["avgSpeedMps"] as? Number)?.toFloat() ?: 0.0f,
                        polylinePoints = finalPoints,
                        createdAt = (data["createdAt"] as? Number)?.toLong() ?: 0L,
                        caloriesKcal = (data["caloriesKcal"] as? Number)?.toInt() ?: 0,
                        elevationGainM = (data["elevationGainM"] as? Number)?.toFloat() ?: 0f,
                        elevationLossM = (data["elevationLossM"] as? Number)?.toFloat() ?: 0f,
                        activityType = ActivityType.Companion.fromString(activityTypeStr),
                        isSmoothed = data["isSmoothed"] as? Boolean ?: false
                    )
                } catch (e: Exception) {
                    null
                }
            }
            Pair(sessions, snapshot.documents.lastOrNull())
        } catch (e: Exception) {
            Pair(emptyList(), null)
        }
    }
}

package com.example.myapplication.data.repository

import android.util.Log
import com.example.myapplication.domain.model.ActivityType
import com.example.myapplication.domain.model.LocationPoint
import com.example.myapplication.domain.model.RunSession
import com.example.myapplication.domain.repository.WorkoutRepository
import com.example.myapplication.data.store.FirestoreHelper
import com.google.firebase.firestore.DocumentReference
import com.google.firebase.firestore.DocumentSnapshot
import com.google.firebase.firestore.Query
import kotlinx.coroutines.Dispatchers
import kotlinx.coroutines.NonCancellable
import kotlinx.coroutines.tasks.await
import kotlinx.coroutines.withContext

class FirestoreWorkoutRepository : WorkoutRepository {

    override suspend fun getWeeklyDoneCount(email: String, startEpochSeconds: Long): Int {
        val startEpochMs = startEpochSeconds * 1000L
        return try {
            val ref = FirestoreHelper.getCurrentUserDocRef()
            val querySnapshot = ref.collection("workoutSessions")
                .whereGreaterThanOrEqualTo("timestamp", startEpochMs)
                .get()
                .await()
            querySnapshot.documents.count { doc ->
                (doc.getString("type") ?: "regular") == "regular"
            }
        } catch (e: Exception) {
            -1
        }
    }

    /**
     * [NonCancellable]: workoutSession dokument mora biti shranjen v Firestore v celoti.
     * Preklicana operacija po .add() klicu (pred .await()) bi se v Firestoreu izvedla,
     * a klicatelj nikoli ne bi dobil potrditve — tiha izguba podatkov.
     */
    override suspend fun saveWorkoutSession(email: String, workoutDoc: Map<String, Any>): Boolean =
        withContext(Dispatchers.IO + NonCancellable) {
            try {
                val ref = FirestoreHelper.getCurrentUserDocRef()
                ref.collection("workoutSessions").add(workoutDoc).await()
                true
            } catch (e: Exception) {
                false
            }
        }

    /**
     * Naloži GPS točke za sesijo — poskusi v vrstnem redu:
     *  1. Sub-kolekcija `gps_points` (nova naprava / nova pot)
     *  2. Sub-kolekcija `points` (po migracijskem načrtu GPS_POINTS_MIGRATION_PLAN.md)
     *  3. Inline `polylinePoints` array v dokumentu (stari format, backwards compat)
     *
     * Pot: users/{uid}/runSessions/{docId}/gps_points  ali  .../points
     */
    private suspend fun loadGpsPoints(
        sessionRef: DocumentReference,
        inlinePoints: List<LocationPoint>
    ): List<LocationPoint> {
        // 1. Poskusi gps_points subcollection
        try {
            val gpsSnap = sessionRef.collection("gps_points")
                .orderBy("chunkIndex")
                .get().await()
            if (!gpsSnap.isEmpty) {
                val pts = gpsSnap.documents.flatMap { doc ->
                    @Suppress("UNCHECKED_CAST")
                    val rawPts = doc.get("pts") as? List<Map<String, Any>> ?: emptyList()
                    rawPts.mapNotNull { pt ->
                        try {
                            LocationPoint(
                                latitude = (pt["lat"] as? Number)?.toDouble()
                                    ?: return@mapNotNull null,
                                longitude = (pt["lng"] as? Number)?.toDouble()
                                    ?: return@mapNotNull null,
                                altitude = (pt["alt"] as? Number)?.toDouble() ?: 0.0,
                                speed = (pt["spd"] as? Number)?.toFloat() ?: 0f,
                                accuracy = 0f,
                                timestamp = (pt["ts"] as? Number)?.toLong() ?: 0L
                            )
                        } catch (e: Exception) {
                            Log.e("WorkoutRepo", "❌ gps_points točka parse napaka @ ${sessionRef.path}: ${e.message}", e)
                            null
                        }
                    }
                }
                if (pts.isNotEmpty()) {
                    Log.d("WorkoutRepo", "GPS: ${pts.size} točk iz gps_points @ ${sessionRef.path}")
                    return pts
                } else {
                    Log.w("WorkoutRepo", "⚠️ gps_points subcollection obstaja ampak je prazna @ ${sessionRef.path}")
                }
            } else {
                Log.d("WorkoutRepo", "GPS: gps_points subcollection prazna @ ${sessionRef.path}")
            }
        } catch (e: Exception) {
            Log.e("WorkoutRepo", "❌ gps_points fetch napaka @ ${sessionRef.path}: ${e.message}", e)
        }

        // 2. Poskusi `points` subcollection (GPS_POINTS_MIGRATION_PLAN format)
        try {
            val pointsSnap = sessionRef.collection("points")
                .orderBy("chunkIndex")
                .get().await()
            if (!pointsSnap.isEmpty) {
                val pts = pointsSnap.documents.flatMap { doc ->
                    @Suppress("UNCHECKED_CAST")
                    val rawPts = doc.get("pts") as? List<Map<String, Any>> ?: emptyList()
                    rawPts.mapNotNull { pt ->
                        try {
                            LocationPoint(
                                latitude = (pt["lat"] as? Number)?.toDouble()
                                    ?: return@mapNotNull null,
                                longitude = (pt["lng"] as? Number)?.toDouble()
                                    ?: return@mapNotNull null,
                                altitude = (pt["alt"] as? Number)?.toDouble() ?: 0.0,
                                speed = 0f, accuracy = 0f,
                                timestamp = (pt["ts"] as? Number)?.toLong() ?: 0L
                            )
                        } catch (e: Exception) {
                            Log.e("WorkoutRepo", "❌ points točka parse napaka @ ${sessionRef.path}: ${e.message}", e)
                            null
                        }
                    }
                }
                if (pts.isNotEmpty()) {
                    Log.d("WorkoutRepo", "GPS: ${pts.size} točk iz points sub-kolekcije @ ${sessionRef.path}")
                    return pts
                } else {
                    Log.w("WorkoutRepo", "⚠️ points subcollection obstaja ampak je prazna @ ${sessionRef.path}")
                }
            } else {
                Log.d("WorkoutRepo", "GPS: points subcollection prazna @ ${sessionRef.path}")
            }
        } catch (e: Exception) {
            Log.e("WorkoutRepo", "❌ points subcollection fetch napaka @ ${sessionRef.path}: ${e.message}", e)
        }

        // 3. Fallback: inline polylinePoints (stari format)
        Log.d("WorkoutRepo", "GPS fallback: inline polylinePoints (${inlinePoints.size} točk) @ ${sessionRef.path}")
        return inlinePoints
    }

    override suspend fun getRunSessions(userId: String, startAfterDoc: Any?, limit: Int): Pair<List<RunSession>, Any?> {
        return try {
            val userRef = FirestoreHelper.getCurrentUserDocRef()
            var query = userRef
                .collection("runSessions")
                .orderBy("createdAt", Query.Direction.DESCENDING)
                .limit(limit.toLong())

            if (startAfterDoc is DocumentSnapshot) {
                query = query.startAfter(startAfterDoc)
            }

            val snapshot = query.get().await()
            val sessions = snapshot.documents.mapNotNull { doc ->
                try {
                    val data = doc.data ?: return@mapNotNull null
                    // Preberi inline polylinePoints (fallback za stare dokumente)
                    val inlinePoints = try {
                        @Suppress("UNCHECKED_CAST")
                        val rawPts = data["polylinePoints"] as? List<Map<String, Any>>
                        rawPts?.mapNotNull { pt ->
                            try {
                                LocationPoint(
                                    latitude = (pt["latitude"] as? Number
                                        ?: pt["lat"] as? Number)?.toDouble()
                                        ?: return@mapNotNull null,
                                    longitude = (pt["longitude"] as? Number
                                        ?: pt["lng"] as? Number)?.toDouble()
                                        ?: return@mapNotNull null,
                                    altitude = (pt["altitude"] as? Number
                                        ?: pt["alt"] as? Number)?.toDouble() ?: 0.0,
                                    speed = (pt["speed"] as? Number
                                        ?: pt["spd"] as? Number)?.toFloat() ?: 0f,
                                    accuracy = (pt["accuracy"] as? Number
                                        ?: pt["acc"] as? Number)?.toFloat() ?: 0f,
                                    timestamp = (pt["timestamp"] as? Number
                                        ?: pt["ts"] as? Number)?.toLong() ?: 0L
                                )
                            } catch (_: Exception) { null }
                        } ?: emptyList()
                    } catch (_: Exception) { emptyList() }

                    // ── GPS Firestore Data Link ───────────────────────────────────────────
                    // Sub-kolekcijo beremo SAMO ko inline točk ni (npr. drugi telefon, stari zapis).
                    // FIX N+1: prej je RUNNING/CYCLING/WALKING vedno sprožil 2 dodatna get() klica
                    // (gps_points + points subcollection) — tudi ko so bile inline točke prisotne.
                    // Rezultat: 15 tekov × 2 klica = 30 nepotrebnih roundtrip-ov (~2-3s zamude).
                    val activityTypeStr = data["activityType"] as? String ?: ""
                    val needsSubFetch = inlinePoints.isEmpty()
                    val finalPoints = if (needsSubFetch) {
                        loadGpsPoints(doc.reference, inlinePoints)
                    } else inlinePoints
                    // ──────────────────────────────────────────────────────────────────────

                    RunSession(
                        id = data["id"] as? String ?: "",
                        userId = data["userId"] as? String ?: "",
                        startTime = (data["startTime"] as? Number)?.toLong() ?: 0L,
                        endTime = (data["endTime"] as? Number)?.toLong() ?: 0L,
                        durationSeconds = (data["durationSeconds"] as? Number)?.toInt() ?: 0,
                        distanceMeters = (data["distanceMeters"] as? Number)?.toDouble() ?: 0.0,
                        maxSpeedMps = (data["maxSpeedMps"] as? Number)?.toFloat() ?: 0.0f,
                        avgSpeedMps = (data["avgSpeedMps"] as? Number)?.toFloat() ?: 0.0f,
                        polylinePoints = finalPoints,
                        createdAt = (data["createdAt"] as? Number)?.toLong() ?: 0L,
                        caloriesKcal = (data["caloriesKcal"] as? Number)?.toInt() ?: 0,
                        elevationGainM = (data["elevationGainM"] as? Number)?.toFloat() ?: 0f,
                        elevationLossM = (data["elevationLossM"] as? Number)?.toFloat() ?: 0f,
                        activityType = ActivityType.Companion.fromString(activityTypeStr),
                        isSmoothed = data["isSmoothed"] as? Boolean ?: false
                    )
                } catch (e: Exception) {
                    null
                }
            }
            Pair(sessions, snapshot.documents.lastOrNull())
        } catch (e: Exception) {
            Pair(emptyList(), null)
        }
    }
}

package com.example.myapplication.data.repository

import android.util.Log
import com.example.myapplication.network.FatSecretApi
import com.example.myapplication.network.FoodDetail
import com.example.myapplication.network.FoodSummary
import com.example.myapplication.network.RecipeDetail
import com.example.myapplication.network.RecipeSummary
import com.example.myapplication.data.store.FirestoreHelper
import com.google.firebase.firestore.DocumentSnapshot
import com.google.firebase.firestore.FieldValue
import com.google.firebase.firestore.QuerySnapshot
import com.google.firebase.firestore.SetOptions
import kotlinx.coroutines.channels.awaitClose
import kotlinx.coroutines.flow.Flow
import kotlinx.coroutines.flow.callbackFlow
import kotlinx.coroutines.tasks.await

/**
 * Singleton implementacija repozitorija,
 * ki skrbi tako za FatSecret API Iskanje kot za Firestore logiranje.
 * UI ne sme več sam logirati v bazo.
 *
 * Faza 29.8: implementira [NutritionRepository] vmesnik → NutritionViewModel
 * ga prejme prek Dependency Injection (konstruktor) in ne kliče tega objekta direktno.
 */
object FoodRepositoryImpl : NutritionRepository {

    suspend fun searchFoodByName(query: String, maxResults: Int = 20): List<FoodSummary> {
        return FatSecretApi.searchFoods(query, 1, maxResults)
    }

    suspend fun getFoodAutocomplete(query: String, maxResults: Int = 5): List<String> {
        return FatSecretApi.getFoodAutocomplete(query, maxResults).map { it.suggestion }
    }

    suspend fun getFoodDetail(id: String): FoodDetail {
        return FatSecretApi.getFoodDetail(id)
    }

    suspend fun searchRecipes(query: String, maxResults: Int = 20): List<RecipeSummary> {
        return FatSecretApi.searchRecipes(query, 1, maxResults)
    }

    suspend fun getRecipeDetail(id: String): RecipeDetail {
        return FatSecretApi.getRecipeDetail(id)
    }

    override fun observeCustomMeals(uid: String): Flow<QuerySnapshot> = callbackFlow {
        val listener = FirestoreHelper.getUserRef(uid)
            .collection("customMeals")
            .addSnapshotListener { snaps, error ->
                if (error != null) {
                    close(error)
                    return@addSnapshotListener
                }
                if (snaps != null) {
                    trySend(snaps)
                }
            }
        awaitClose { listener.remove() }
    }

    override fun observeDailyLog(uid: String, todayId: String): Flow<DocumentSnapshot> = callbackFlow {
        val docRef = FirestoreHelper.getUserRef(uid).collection("dailyLogs").document(todayId)
        val listener = docRef.addSnapshotListener { doc, error ->
            Log.d("DEBUG_DATA", "Poslušam dokument: ${docRef.path}")
            if (error != null) {
                close(error)
                return@addSnapshotListener
            }
            if (doc != null) {
                Log.d("DEBUG_DATA", "Novo stanje iz baze (dailyLog): ${doc.data}")
                trySend(doc)
            }
        }
        awaitClose { listener.remove() }
    }

    suspend fun logCustomMeal(name: String, itemsList: List<Any>): String {
        val docRef = FirestoreHelper.getCurrentUserDocRef()
        val mealData = mapOf(
            "name" to name,
            "items" to itemsList,
            "createdAt" to FieldValue.serverTimestamp()
        )

        // Zamenjavo klasičnega .add na Batch ali Transaction
        return FirestoreHelper.getDb().runTransaction { transaction ->
            val newRef = docRef.collection("customMeals").document()
            transaction.set(newRef, mealData)
            newRef.id
        }.await()
    }

    suspend fun deleteCustomMeal(mealId: String) {
        val docRef = FirestoreHelper.getCurrentUserDocRef()
        val mealRef = docRef.collection("customMeals").document(mealId)

        FirestoreHelper.getDb().runTransaction { transaction ->
            transaction.delete(mealRef)
        }.await()
    }

    override suspend fun logWater(amountMl: Int, dateStr: String) {
        val docRef = FirestoreHelper.getCurrentUserDocRef()
        val dailyLogRef = docRef.collection("dailyLogs").document(dateStr)
        val data = mapOf(
            "date" to dateStr,
            "waterMl" to amountMl,
            "updatedAt" to FieldValue.serverTimestamp()
        )
        FirestoreHelper.getDb().runTransaction { transaction ->
            transaction.set(dailyLogRef, data, SetOptions.merge())
            null
        }.await()
    }

    /**
     * Faza 13b — Briši sledeni vnos hrane iz dailyLogs/{dateStr}/items.
     *
     * Atomarna Firestore transakcija:
     *  1. Prebere obstoječi seznam items
     *  2. Poišče element po id polju in ga odstrani
     *  3. Odšteje caloriesKcal od consumedCalories (coerceAtLeast(0.0) prepreči negativne)
     *
     * @param foodId      UUID vnosa (polje "id" v items mapi)
     * @param dateStr     Datum v obliki "YYYY-MM-DD"
     * @param caloriesKcal Kalorije tega vnosa za odštevanje
     */
    override suspend fun removeFoodItem(foodId: String, dateStr: String, caloriesKcal: Double) {
        val docRef      = FirestoreHelper.getCurrentUserDocRef()
        val dailyLogRef = docRef.collection("dailyLogs").document(dateStr)

        FirestoreHelper.getDb().runTransaction { transaction ->
            val snapshot = transaction.get(dailyLogRef)

            // Preberi obstoječi items seznam
            @Suppress("UNCHECKED_CAST")
            val existingItems = (snapshot.get("items") as? List<Map<String, Any>>) ?: emptyList()

            // Poišči in odstrani element po id — varno tudi če id ne obstaja
            val updatedItems = existingItems.filter { item ->
                (item["id"] as? String) != foodId
            }

            // Odštej kalorije — coerceAtLeast(0.0) prepreči negativne vrednosti
            val currentConsumed = (snapshot.get("consumedCalories") as? Number)?.toDouble() ?: 0.0
            val newConsumed     = (currentConsumed - caloriesKcal).coerceAtLeast(0.0)

            transaction.update(dailyLogRef, mapOf(
                "items"             to updatedItems,
                "consumedCalories"  to newConsumed,
                "updatedAt"         to FieldValue.serverTimestamp()
            ))
            null
        }.await()
    }

    override suspend fun logFood(foodItem: Map<String, Any>, dateStr: String) {
        val docRef = FirestoreHelper.getCurrentUserDocRef()
        val dailyLogRef = docRef.collection("dailyLogs").document(dateStr)
        val calories = (foodItem["caloriesKcal"] as? Number)?.toDouble() ?: 0.0

        FirestoreHelper.getDb().runTransaction { transaction ->
            val snapshot = transaction.get(dailyLogRef)
            val currentConsumed = (snapshot.get("consumedCalories") as? Number)?.toDouble() ?: 0.0
            val newConsumed = currentConsumed + calories

            val data = mutableMapOf<String, Any>(
                "consumedCalories" to newConsumed,
                "items" to FieldValue.arrayUnion(foodItem),
                "updatedAt" to FieldValue.serverTimestamp()
            )
            // Ensure the date field is present
            if (!snapshot.exists() || !snapshot.contains("date")) {
                data["date"] = dateStr
            }

            transaction.set(dailyLogRef, data, SetOptions.merge())
            null
        }.await()
    }

    /** Faza 29.8: preseljeno iz NutritionViewModel.getCustomMealItems()
     *  Faza 31.7: FirestoreHelper.getUserRef(uid) namesto direktnega db.collection("users")...
     *  → FirestoreHelper centralizira email/UID routing logiko (migracija). */
    override suspend fun getCustomMealItems(uid: String, mealId: String): List<Map<String, Any>>? {
        return try {
            val doc = FirestoreHelper.getUserRef(uid)
                .collection("customMeals").document(mealId)
                .get().await()
            if (doc.exists()) doc.get("items") as? List<Map<String, Any>>
            else null
        } catch (e: Exception) {
            null
        }
    }
}

